// ==========================================
// PATH 1: MERGE PART1 TEXTS (CRASH PROOF VERSION)
// Combines direct_text and txt_file into one clean output
// Calculates word counts internally to prevent errors
// ==========================================

const item = $input.item;
const items = item.json.data || []; // Safely get the array, default to empty if missing

// Helper function to safely count words
function countWords(str) {
  return str ? str.trim().split(/\s+/).length : 0;
}

// Collect all text contents
const textSources = items.map((textItem) => {
  // Safe extraction of content
  const content = textItem.content || "";

  return {
    source: textItem.source || "unknown_source",
    content: content,
    // We calculate these NOW so we don't rely on previous nodes
    word_count: countWords(content),
    character_count: content.length
  };
});

// Combine all texts with source labels
const combinedText = textSources.map(s => {
  return `--- Source: ${s.source.toUpperCase()} ---\n${s.content}`;
}).join('\n\n');

// Calculate totals
const totalWords = textSources.reduce((sum, s) => sum + s.word_count, 0);
const totalChars = textSources.reduce((sum, s) => sum + s.character_count, 0);

// Safe metadata extraction (check if the first item exists)
const meta = items.length > 0 && items[0].metadata ? items[0].metadata : {};

return {
  json: {
    path: "part1_text",
    route: "part1",
    step: "ask_rufus",
    data_type: "text",

    // Combined content
    final_text: combinedText,

    // Source tracking
    text_sources: textSources.map(s => s.source),
    source_count: textSources.length,

    // Statistics
    total_words: totalWords,
    total_characters: totalChars,

    // Metadata (Safe fallback)
    metadata: {
      submittedAt: meta.submittedAt || new Date().toISOString(),
      formMode: meta.formMode || "test",
      processing_complete: true,
      ready_for_ai: true
    }
  }
};

// =========================================================
// RUFUS UNIVERSAL SPLITTER & CLEANER
// Fixes: Spaces in filenames, Binary mapping for Gemini
// =========================================================

const outputs = [];
const item = $input.item;
const json = item.json;
const binary = item.binary || {};

// --- Helper: Normalize strings for easy matching ---
// Removes special chars, spaces, and underscores to compare "photo 1" equal to "photo_1"
function normalize(str) {
  return str ? str.toLowerCase().replace(/[^a-z0-9]/g, '') : '';
}

// --- 1. HANDLE TEXT (Direct Input) ---
// Loop through JSON keys to find direct text inputs
for (const key of Object.keys(json)) {
  const normKey = normalize(key);

  // Look for text fields (Part 1 Text)
  if (normKey.includes("part1") && normKey.includes("text") && typeof json[key] === 'string') {
    if (json[key].trim()) {
      outputs.push({
        json: {
          route: "part1",
          data_type: "text",
          source: "direct_input",
          content: json[key]
        }
      });
    }
  }
}

// --- 2. HANDLE BINARY FILES (Screenshots & TXT) ---
// We loop through ALL binary keys directly. No guessing names.
for (const key of Object.keys(binary)) {
  const fileData = binary[key];
  const normKey = normalize(key);
  const mimeType = fileData.mimeType || "";
  const fileName = fileData.fileName || "unknown";

  // --> Identify Part 1 vs Part 2 based on the Field Name (Key)
  let route = "";
  if (normKey.includes("part1") || normKey.includes("askrufus")) route = "part1";
  else if (normKey.includes("part2") || normKey.includes("specificinfo")) route = "part2";

  if (!route) continue; // Skip if it doesn't match our fields

  // --> TYPE A: Text Files (.txt)
  if (mimeType.includes("text") || fileName.endsWith(".txt")) {
    try {
      // Convert binary to text immediately
      const fileBuffer = await this.helpers.getBinaryDataBuffer(0, key);
      const textContent = fileBuffer.toString('utf8');

      outputs.push({
        json: {
          route: route,
          data_type: "text",
          source: "txt_file",
          filename: fileName,
          content: textContent
        }
      });
    } catch (e) {
      // Ignore read errors
    }
  }

  // --> TYPE B: Images (PNG/JPG) - PREPARE FOR GEMINI
  else if (mimeType.includes("image")) {
    outputs.push({
      json: {
        route: route, // "part1" or "part2"
        data_type: "screenshots", // Used by your Switch node
        source: "screenshot",
        filename: fileName
      },
      binary: {
        // CRITICAL FIX: We put the image into the default 'data' property
        // This is exactly where Gemini/AI nodes look for it.
        data: fileData 
      }
    });
  }
}

return outputs;

// ==========================================
// PATH 1: MERGE SCREENSHOT ANALYSIS
// Combines multiple Gemini OCR outputs into one clean string
// ==========================================

// Variable to store merged text
let fullText = "";
let validScreenshots = 0;

// Loop through all input items (each item is one screenshot analysis)
for (let i = 0; i < items.length; i++) {
  const item = items[i].json;

  // 1. Robustly find the text output from Gemini
  // Based on your JSON, it is located in 'content.parts[0].text'
  let text = "";

  if (item.content && item.content.parts && item.content.parts[0]) {
    text = item.content.parts[0].text;
  } else if (item.text) {
    // Fallback for different Gemini node versions
    text = item.text;
  } else if (item.output) {
    // Fallback for generic AI nodes
    text = item.output;
  }

  // 2. Append if text was found
  if (text) {
    validScreenshots++;
    fullText += `--- [Screenshot ${i + 1} Analysis] ---\n${text}\n\n`;
  }
}

// 3. Calculate Stats
const wordCount = fullText ? fullText.trim().split(/\s+/).length : 0;

// 4. Return formatted object ready for final merge
return {
  json: {
    path: "part1_screenshots", // Different path name to avoid collision with text
    route: "part1",
    step: "ask_rufus_ocr",
    data_type: "screenshots_analysis",

    // The main payload
    final_text: fullText.trim(),

    // Stats
    screenshot_count: validScreenshots,
    word_count: wordCount,

    // Metadata
    metadata: {
      processed_at: new Date().toISOString(),
      ready_for_merge: true
    }
  }
};

// ==========================================
// PATH 2: MERGE TAGS & CONTENT (FULL VERSION)
// Keeps ALL text context + Extracts Tags
// ==========================================

let fullText = "";
let allTags = new Set(); 

// Loop through all items (Gemini results)
for (let i = 0; i < items.length; i++) {
  const item = items[i].json;

  // 1. Get the text output safely
  let text = "";
  if (item.content && item.content.parts && item.content.parts[0]) {
    text = item.content.parts[0].text;
  } else if (item.text) {
    text = item.text;
  } else if (item.output) {
    text = item.output;
  }

  // 2. Append to Full Text (This preserves the "Text Body")
  if (text) {
    fullText += `--- [Specific Info ${i + 1}] ---\n${text.trim()}\n\n`;

    // 3. Extract Tags (Heuristic: Short phrases are likely tags)
    // Remove markdown
    const cleanText = text.replace(/```json/g, '').replace(/```/g, '').trim();

    // Split by lines or commas to find potential tags
    const lines = cleanText.split(/,|\n/);

    lines.forEach(line => {
      const cleanLine = line.trim();
      // Filter: Keep it if it's not empty, not too long (likely a tag), and not a sentence
      if (cleanLine && cleanLine.length < 40 && !cleanLine.endsWith('.')) {
        allTags.add(cleanLine);
      }
    });
  }
}

// Convert Set back to Array
const uniqueTags = Array.from(allTags);
const wordCount = fullText ? fullText.trim().split(/\s+/).length : 0;

return {
  json: {
    path: "part2_tags",
    route: "part2",
    step: "specific_info_tags",
    data_type: "tags_analysis",

    // ✅ NEW: The Full Text Body is now saved here!
    final_text: fullText.trim(),

    // The Tags (Cleaned up)
    amazon_tags: uniqueTags,

    // Stats
    tag_count: uniqueTags.length,
    word_count: wordCount,

    // Metadata
    metadata: {
      processed_at: new Date().toISOString(),
      ready_for_merge: true
    }
  }
};

// ==========================================
// CONSOLIDATE PART 1
// Stitches Text + Screenshot Context into one big string
// ==========================================

let combinedContext = "";
let totalWords = 0;

// Loop through the items (Item 1: Text, Item 2: Screenshots)
for (const item of items) {
  if (item.json.final_text) {
     // Add a header based on the data type
     const type = item.json.data_type === 'text' ? "TEXT & FILES" : "SCREENSHOTS OCR";

     combinedContext += `\n\n=== PART 1 SECTION: ${type} ===\n`;
     combinedContext += item.json.final_text;

     // Sum up words if available
     if (item.json.total_words) totalWords += item.json.total_words;
     if (item.json.word_count) totalWords += item.json.word_count;
  }
}

return {
  json: {
    source: "part1_complete",
    // This is the variable your Interrogator AI will read
    part1_full_context: combinedContext.trim(),

    // Total stats
    total_word_count: totalWords,

    metadata: {
      ready_for_final_merge: true
    }
  }
};

// ==========================================
// DECODER: FORMAT QUESTIONS FOR HUMAN
// Turns AI JSON into a clean copy-paste list
// ==========================================

const response = items[0].json.content.parts[0].text;
// Remove Markdown code blocks
const cleanJson = response.replace(/```json/g, '').replace(/```/g, '').trim();
const data = JSON.parse(cleanJson);

const questions = data.auditor_report.trap_questions;
let formattedOutput = "=== 📋 COPY THESE QUESTIONS TO ASK RUFUS ===\n\n";

questions.forEach((q, index) => {
  formattedOutput += `QUESTION ${index + 1} (${q.type}):\n`;
  formattedOutput += `${q.question}\n\n`;
});

return {
  json: {
    human_readable_list: formattedOutput,
    raw_questions: questions
  }
};

// ==========================================
// DECODER: FORMAT ANALYST INSIGHTS
// Turns Product Insight JSON into a Readable Report
// ==========================================

// 1. Get the text output from Gemini safely
let responseText = "";
if (items[0].json.content && items[0].json.content.parts) {
    responseText = items[0].json.content.parts[0].text;
} else if (items[0].json.output) {
    responseText = items[0].json.output;
}

// 2. Clean and Parse JSON
const cleanJson = responseText.replace(/```json/g, '').replace(/```/g, '').trim();
let data = {};
try {
    data = JSON.parse(cleanJson);
} catch (e) {
    return { json: { error: "Failed to parse JSON", raw: responseText } };
}

const insight = data.product_insight;
let formattedOutput = "=== 💡 PRODUCT INSIGHT REPORT (THE DREAM) ===\n\n";

// 3. Build the Report
formattedOutput += `👤 **Target Persona:** ${insight.customer_profile}\n`;
formattedOutput += `❤️ **Key Desire:** ${insight.key_desire}\n`;
formattedOutput += `😱 **Key Fear:** ${insight.key_fear}\n\n`;
formattedOutput += "--- 🛡️ VALIDATION QUESTIONS ---\n\n";

if (insight.validation_questions) {
    insight.validation_questions.forEach((q, index) => {
        formattedOutput += `QUESTION ${index + 1} (${q.type}):\n`;
        formattedOutput += `❓ **Ask Rufus:** "${q.question}"\n`;
        formattedOutput += `💡 **Why:** ${q.insight_origin}\n\n`;
    });
}

return {
  json: {
    human_readable_report: formattedOutput,
    raw_insight: insight
  }
};

// ==========================================
// DECODER: FORMAT PART 2 AUDIT QUESTIONS
// Turns Official Info Traps into a List
// ==========================================

// 1. Get Gemini Response
let responseText = "";
if (items[0].json.content && items[0].json.content.parts) {
    responseText = items[0].json.content.parts[0].text;
} else if (items[0].json.output) {
    responseText = items[0].json.output;
}

// 2. Parse JSON
const cleanJson = responseText.replace(/```json/g, '').replace(/```/g, '').trim();
let data = {};
try {
    data = JSON.parse(cleanJson);
} catch (e) {
    return { json: { error: "JSON Parse Error", raw: responseText } };
}

const questions = data.auditor_report.trap_questions;
let formattedOutput = "=== 📋 PART 2 TRAP QUESTIONS (ATTACKING OFFICIAL INFO) ===\n\n";

questions.forEach((q, index) => {
  formattedOutput += `QUESTION ${index + 1} (${q.type}):\n`;
  formattedOutput += `${q.question}\n\n`;
});

return {
  json: {
    human_readable_list: formattedOutput,
    raw_questions: questions
  }
};

// ==========================================
// DECODER: FORMAT PART 2 MARKETING INSIGHTS
// Turns Official Marketing Promises into a Report
// ==========================================

// 1. Get Gemini Response
let responseText = "";
if (items[0].json.content && items[0].json.content.parts) {
    responseText = items[0].json.content.parts[0].text;
} else if (items[0].json.output) {
    responseText = items[0].json.output;
}

// 2. Parse JSON
const cleanJson = responseText.replace(/```json/g, '').replace(/```/g, '').trim();
let data = {};
try {
    data = JSON.parse(cleanJson);
} catch (e) {
    return { json: { error: "JSON Parse Error", raw: responseText } };
}

const insight = data.marketing_insight;
let formattedOutput = "=== 🌟 PART 2 MARKETING INSIGHT (OFFICIAL PROMISE) ===\n\n";

formattedOutput += `🏷️ **Core Identity:** ${insight.core_identity}\n`;
formattedOutput += `🔥 **Key Selling Point:** ${insight.key_selling_point}\n\n`;
formattedOutput += "--- ✅ CONFIRMATION QUESTIONS ---\n\n";

insight.confirmation_questions.forEach((q, index) => {
  formattedOutput += `QUESTION ${index + 1} (${q.type}):\n`;
  formattedOutput += `❓ **Ask Rufus:** "${q.question}"\n`;
  formattedOutput += `💡 **Why:** ${q.insight_origin}\n\n`;
});

return {
  json: {
    human_readable_report: formattedOutput,
    raw_insight: insight
  }
};

// ==========================================
// INTELLIGENCE AGGREGATOR
// Combines insights from Part 1 & Part 2 into one Master Object
// Handles data from 'Append' merge strategy
// ==========================================

// Initialize containers
let p1_audit = {};
let p1_insight = {};
let p2_audit = {};
let p2_insight = {};

// Loop through all incoming items (from the Append Merge)
for (const item of items) {
  const json = item.json;

  // --- DETECT PART 1 DATA (User Context) ---
  // Auditor: Look for P1 specific trap types or content
  if (json.human_readable_list && (json.human_readable_list.includes("Ambiguity Trap") || json.human_readable_list.includes("Contradiction Trap"))) {
     p1_audit = { weaknesses: json.raw_questions };
  }
  // Analyst: Look for "Target Persona" which is specific to P1
  if (json.raw_insight && json.raw_insight.customer_profile) {
     p1_insight = json.raw_insight;
  }

  // --- DETECT PART 2 DATA (Official Specs) ---
  // Auditor: Look for P2 specific trap types
  if (json.human_readable_list && (json.human_readable_list.includes("Safety Silence") || json.human_readable_list.includes("Missing Spec"))) {
     p2_audit = { specs_gaps: json.raw_questions };
  }
  // Analyst: Look for "Core Identity" which is specific to P2
  if (json.raw_insight && json.raw_insight.core_identity) {
     p2_insight = json.raw_insight;
  }
}

// Construct the Master Intelligence Object
// This maps all the disjointed insights into a strategic structure
const master_intelligence = {
  // 1. Who are we selling to? (From P1 Analyst)
  target_customer: {
    persona: p1_insight.customer_profile || "Unknown",
    desire: p1_insight.key_desire || "Unknown",
    fear: p1_insight.key_fear || "Unknown"
  },

  // 2. What is wrong with the competitor/Rufus? (From P1 & P2 Auditors)
  product_risks: [
    ...(p1_audit.weaknesses || []).map(q => `[User Complaint] ${q.reasoning}`),
    ...(p2_audit.specs_gaps || []).map(q => `[Spec Defect] ${q.reasoning}`)
  ],

  // 3. How does Amazon market this? (From P2 Analyst)
  marketing_assets: {
    identity: p2_insight.core_identity || "Unknown",
    selling_point: p2_insight.key_selling_point || "Unknown"
  },

  // 4. Archive of all trap questions for future testing
  trap_questions_archive: {
    p1_traps: p1_audit.weaknesses || [],
    p2_traps: p2_audit.specs_gaps || []
  }
};

return {
  json: {
    sku: "CURRENT_TEST_SKU", 
    timestamp: new Date().toISOString(),
    intelligence: master_intelligence
  }
};

// ==========================================
// DECODER: FINAL STRATEGY REPORT
// Extracts the clean Markdown text for easy reading
// ==========================================

// 1. Get the text output from Gemini safely
let responseText = "";
if (items[0].json.content && items[0].json.content.parts) {
    responseText = items[0].json.content.parts[0].text;
} else if (items[0].json.output) {
    responseText = items[0].json.output;
}

// 2. Clean up any extra JSON formatting/Markdown fences
// (Gemini sometimes wraps the output in ```markdown ... ```)
const cleanReport = responseText
    .replace(/^```markdown\s*/i, '') // Remove starting ```markdown
    .replace(/^```\s*/i, '')         // Remove starting ```
    .replace(/```$/i, '')            // Remove ending ```
    .trim();

// 3. Output as a single clean field
return {
  json: {
    // This field will contain the formatted text
    readable_strategy_report: cleanReport
  }
};

// ==========================================
// REPORT GENERATOR: MARKDOWN TO HTML
// Creates a downloadable file for the strategy
// ==========================================

const markdown = items[0].json.readable_strategy_report || "";

// 1. Simple Converter: Markdown -> HTML
let htmlContent = markdown
    // Convert Headers
    .replace(/^### (.*$)/gim, '<h3 style="color: #2c3e50; border-bottom: 1px solid #eee; padding-bottom: 5px;">$1</h3>')
    .replace(/^## (.*$)/gim, '<h2 style="color: #e67e22; margin-top: 30px;">$1</h2>')
    .replace(/^# (.*$)/gim, '<h1>$1</h1>')
    // Convert Bold
    .replace(/\*\*(.*?)\*\*/gim, '<strong>$1</strong>')
    // Convert Blockquotes (Strategy Sections)
    .replace(/^> (.*$)/gim, '<blockquote style="background: #f1f8ff; border-left: 5px solid #2980b9; padding: 10px; margin: 10px 0;">$1</blockquote>')
    // Convert Lists
    .replace(/^\* (.*$)/gim, '<li>$1</li>')
    // Convert Newlines to Breaks
    .replace(/\n/gim, '<br>');

// 2. Wrap in a professional template
const fullHtml = `
<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<style>
  body { 
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, Arial, sans-serif; 
    line-height: 1.6; 
    color: #333; 
    max-width: 800px; 
    margin: 40px auto; 
    padding: 20px; 
    background-color: #f4f6f8;
  }
  .paper {
    background: white;
    padding: 40px;
    box-shadow: 0 4px 6px rgba(0,0,0,0.1);
    border-radius: 8px;
  }
  li { margin-bottom: 5px; }
  strong { color: #2c3e50; }
</style>
</head>
<body>
  <div class="paper">
    ${htmlContent}
  </div>
</body>
</html>
`;

// 3. Return as a Binary File (Downloadable)
return {
  json: {
    status: "Report Generated Successfully"
  },
  binary: {
    report_file: {
      data: Buffer.from(fullHtml).toString('base64'),
      mimeType: 'text/html',
      fileName: 'Rufus_Strategy_Report.html'
    }
  }
};
